```private static BigInteger compute(BigInteger n) {

        BigInteger sum = new BigInteger("0");

        BigInteger two = new BigInteger("2");

        while(n.mod(two) == 0) {
            sum.add(two);
            n = n.div(two);
            //System.out.println(sum);
        }

        BigInteger div = new BigInteger("3");
        while(div.compareTo(n) < 1) {
            while(n.mod(div) == 0) {
                sum.add(div);
                n = n.div(div);
                //System.out.println(sum);
            }
            div = div.add(two);
        }

        return sum;
    }
